checker_dsl:
EXISTS (`method set`, `method get`) {
  AND {
    (`set method name matches pattern "set%"`),
    (`get method name equals "get" concatenated with the substring of set method name starting from index 3 to the end`),
    (`set method is declared with synchronized modifier`),
    NOT {
      OR {
        (`get method is declared with synchronized modifier`),
        EXISTS (`SynchronizedStmt sync`, `Expr on`) {
          AND {
            (`sync is a descendant (zero or more steps) of get method body`),
            (`on is the synchronized expression of sync`),
            OR {
              AND {
                (`get method is static`),
                (`on is a TypeLiteral`)
              },
              AND {
                (`get method is not static`),
                (`on is a ThisAccess`),
                (`the type of on is a RefType`)
              }
            }
          }
        }
      }
    },
    NOT {
      EXISTS (`Field f`) {
        AND {
          (`f is declared with volatile modifier`),
          (`f is the field accessed by get method as a getter`),
          EXISTS (`FieldWrite fw`) {
            AND {
              (`fw is an access to field f`),
              (`the enclosing callable of fw is set method`)
            }
          }
        }
      }
    }
  }
}
